import{_ as e,o as t,c as a,Q as o}from"./chunks/framework.b67c47e6.js";const m=JSON.parse('{"title":"Multipanel Groups","description":"","frontmatter":{},"headers":[],"relativePath":"guide/management/multipanel_groups/index.md","filePath":"guide/management/multipanel_groups/index.md","lastUpdated":1776440570000}'),i={name:"guide/management/multipanel_groups/index.md"},r=o('<h1 id="multipanel-groups" tabindex="-1">Multipanel Groups <a class="header-anchor" href="#multipanel-groups" aria-label="Permalink to &quot;Multipanel Groups&quot;">​</a></h1><p>Multipanel Groups let you combine multiple wall panels into a single unit that is processed together through the machine. This is a production-level decision — you create groups inside a batch to tell the machine to feed several panels consecutively as one run.</p><p>When a group is <strong>locked</strong>, the entire group is treated as a single logical panel by the report system: Bill of Materials reports use the combined rail length, and machine files (MOB2) are generated as one file for the whole group.</p><div class="info custom-block"><p class="custom-block-title">Feature flag</p><p>Multipanel Groups must be enabled on your company by a Produuz.it administrator. Once enabled, a configuration card appears in each project&#39;s settings and a <strong>Multipanel Groups</strong> tab appears in each batch.</p></div><nav class="table-of-contents"><ul><li><a href="#project-configuration">Project Configuration</a></li><li><a href="#creating-a-group">Creating a Group</a></li><li><a href="#validation-requirements">Validation Requirements</a></li><li><a href="#group-status">Group Status</a></li><li><a href="#locking-a-group">Locking a Group</a></li><li><a href="#report-form-—-assembly-selector">Report Form — Assembly Selector</a></li><li><a href="#bill-of-materials-impact">Bill of Materials Impact</a></li><li><a href="#machine-file-impact-mob2">Machine File Impact (MOB2)</a></li><li><a href="#suggest-groups">Suggest Groups</a></li></ul></nav><h2 id="project-configuration" tabindex="-1">Project Configuration <a class="header-anchor" href="#project-configuration" aria-label="Permalink to &quot;Project Configuration&quot;">​</a></h2><p>Before creating groups, configure the constraints for each project in <strong>Project Settings → Multipanel Groups</strong>.</p><table><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>Min height (mm)</strong></td><td>Minimum panel height allowed in a group.</td></tr><tr><td><strong>Min / Max element width (mm)</strong></td><td>Allowed width range for individual panels.</td></tr><tr><td><strong>Max transport width (mm)</strong></td><td>The combined width of all panels plus gaps must not exceed this value. This is typically the physical limit of the machine or transport system.</td></tr><tr><td><strong>Min / Max element count</strong></td><td>Minimum and maximum number of panels per group.</td></tr><tr><td><strong>Default gap (mm)</strong></td><td>Default gap between elements when creating a new group.</td></tr></tbody></table><h2 id="creating-a-group" tabindex="-1">Creating a Group <a class="header-anchor" href="#creating-a-group" aria-label="Permalink to &quot;Creating a Group&quot;">​</a></h2><p>Navigate to <strong>Batch → Multipanel Groups</strong> and click <strong>New Group</strong>. The creation dialog walks you through four steps:</p><ol><li><strong>Select panels</strong> — choose two or more assemblies from the batch. The selector constrains to consecutive production priorities.</li><li><strong>Set gaps</strong> — define the gap between each pair of adjacent panels (in mm).</li><li><strong>Validate</strong> — run the 8 validation checks (see below). Each requirement shows a pass/fail badge with a detail message.</li><li><strong>Name &amp; confirm</strong> — give the group a name and save. The group is saved with status <strong>valid</strong> (or <strong>invalid</strong> if any checks failed).</li></ol><h2 id="validation-requirements" tabindex="-1">Validation Requirements <a class="header-anchor" href="#validation-requirements" aria-label="Permalink to &quot;Validation Requirements&quot;">​</a></h2><p>All 8 requirements must pass before a group can be locked.</p><table><thead><tr><th>#</th><th>Requirement</th><th>What is checked</th></tr></thead><tbody><tr><td>1</td><td><strong>Height equality</strong></td><td>All panels must have the same height; each must meet the project minimum.</td></tr><tr><td>2</td><td><strong>Width range</strong></td><td>Each panel&#39;s width must be within the configured [min, max] range.</td></tr><tr><td>3</td><td><strong>Element count</strong></td><td>The number of panels must be within [min_count, max_count].</td></tr><tr><td>4</td><td><strong>Framing match</strong></td><td>Top and bottom rail profile, material, and finish must be identical across all panels.</td></tr><tr><td>5</td><td><strong>Consecutive sequence</strong></td><td>Panels must be consecutive in the production priority order and all in the same batch.</td></tr><tr><td>6</td><td><strong>Identical zones</strong></td><td>The set of zone branches (e.g., insulation zones, openings) must be the same across all panels.</td></tr><tr><td>7</td><td><strong>Transport width</strong></td><td>Total combined width (sum of panel widths + all gaps) must not exceed the configured maximum.</td></tr><tr><td>8</td><td><strong>Panel-layer operations</strong></td><td>Saw and milling operations on the panel layer must be equal across all elements.</td></tr></tbody></table><h2 id="group-status" tabindex="-1">Group Status <a class="header-anchor" href="#group-status" aria-label="Permalink to &quot;Group Status&quot;">​</a></h2><table><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><code>draft</code></td><td>Newly created, not yet validated.</td></tr><tr><td><code>valid</code></td><td>All validation checks passed — ready to lock.</td></tr><tr><td><code>invalid</code></td><td>One or more validation checks failed.</td></tr><tr><td><code>locked</code></td><td>Locked for production. Reports and machine files treat the group as a single panel.</td></tr></tbody></table><h2 id="locking-a-group" tabindex="-1">Locking a Group <a class="header-anchor" href="#locking-a-group" aria-label="Permalink to &quot;Locking a Group&quot;">​</a></h2><p>Once a group has <strong>valid</strong> status, open it in the drawer and click <strong>Lock</strong>. On lock:</p><ul><li>The combined rail length (<code>sum of element widths + gaps</code>) is computed and stored.</li><li>The group cannot be edited after this point.</li><li>All reports and machine file generators that include any assembly from this group will treat it as a single combined panel going forward.</li></ul><h2 id="report-form-—-assembly-selector" tabindex="-1">Report Form — Assembly Selector <a class="header-anchor" href="#report-form-—-assembly-selector" aria-label="Permalink to &quot;Report Form — Assembly Selector&quot;">​</a></h2><p>When building a report (BoM, machine files, etc.), the assembly selector is aware of multipanel groups:</p><ul><li>Each assembly that belongs to a group shows a <strong>chip</strong> with the group name and the panel count (e.g. <code>Group A · 3 panels</code>). This makes it easy to spot which assemblies are part of a combined unit.</li><li>A <strong>&quot;Force multipanel selection&quot;</strong> toggle is available on the selector. When enabled, selecting any assembly in a group automatically adds all other assemblies of the same group to the selection. This prevents accidentally generating a report for only part of a locked group.</li></ul><h2 id="bill-of-materials-impact" tabindex="-1">Bill of Materials Impact <a class="header-anchor" href="#bill-of-materials-impact" aria-label="Permalink to &quot;Bill of Materials Impact&quot;">​</a></h2><p>When generating a BoM report (Wood BoM, Plates BoM, etc.) that includes assemblies belonging to a <strong>locked</strong> Multipanel Group:</p><ul><li>The top rail and bottom rail parts are replaced by a single virtual part spanning the full group width.</li><li>The rail <strong>length</strong> in the cut list equals <code>sum of all panel widths + sum of all gaps between panels</code>.</li><li>All other part properties (material, profile, finish, etc.) are taken from the first panel&#39;s rail.</li><li>Non-rail parts from each panel appear individually in the list, as usual.</li><li>Only one row appears per rail category (one top rail, one bottom rail) for the entire group — not one per panel.</li></ul><p>This ensures the cut list reflects the actual piece that goes through the machine, rather than individual per-panel lengths that would be incorrect.</p><div class="tip custom-block"><p class="custom-block-title">Example</p><p>Two panels: 1200 mm and 900 mm wide, with a 10 mm gap between them. Combined rail length = 1200 + 900 + 10 = <strong>2110 mm</strong>. The BoM shows one top rail and one bottom rail, each 2110 mm long.</p></div><h2 id="machine-file-impact-mob2" tabindex="-1">Machine File Impact (MOB2) <a class="header-anchor" href="#machine-file-impact-mob2" aria-label="Permalink to &quot;Machine File Impact (MOB2)&quot;">​</a></h2><p>When generating a MOB2 machine file for a batch or selection that includes assemblies from a <strong>locked</strong> Multipanel Group:</p><ul><li>A <strong>single <code>.mob2</code> file</strong> is generated for the entire group, named after the group.</li><li>The file is placed in the batch folder as <code>&lt;phase&gt;/&lt;batch&gt;/&lt;group_name&gt;.mob2</code>.</li><li>Part positions within the combined file are offset correctly: parts from panel 2 are placed after panel 1, with the configured gap applied — so the machine sees the full combined run in the correct order.</li><li>The revision field is left blank for group files (since a group has no single design revision).</li><li>If only some assemblies of a locked group are included in the selection, the group is still treated as a whole — the file covers all panels in the group.</li></ul><h2 id="suggest-groups" tabindex="-1">Suggest Groups <a class="header-anchor" href="#suggest-groups" aria-label="Permalink to &quot;Suggest Groups&quot;">​</a></h2><p>Use the <strong>Suggest</strong> function on a batch to automatically find candidate groups. The suggestion engine scans the batch&#39;s production priority order with a sliding window and runs lightweight validation (skipping the framing and panel-layer checks) to surface likely valid combinations, sorted by start priority.</p><p>Suggestions are not saved automatically — review them and create the ones that make sense for your production run.</p>',33),n=[r];function l(s,d,c,h,p,u){return t(),a("div",null,n)}const f=e(i,[["render",l]]);export{m as __pageData,f as default};
